css:
/*
借鉴了深蓝磨砂主题，但是目前有bug
 */

/* === 1. 颜色变量与基础设置 (深蓝Mica风格) === */
:root {
  /* 背景色系 Backgrounds */
  --ui-bg-primary: #0a1929;         /* 主背景色 */
  --ui-bg-secondary: #132f4c;       /* 次要背景 (UI元素) */
  --ui-bg-tertiary: #011627;        /* 最深背景 (代码块内部) */

  /* 聊天气泡 (使用半透明以支持磨砂效果) Chat Bubbles (Semi-transparent for Mica) */
  --ui-bg-user-mica: rgba(30, 58, 95, 0.8);    /* 用户消息 (深蓝) */
  --ui-bg-ai-mica: rgba(20, 30, 45, 0.8);      /* AI消息 (灰蓝) */
  /* 纯色备用 (用于no-blur模式) Solid Fallbacks */
  --ui-bg-user-solid: #1e3a5f;
  --ui-bg-ai-solid: #141e2d;

  /* 文本色系 Text Colors */
  --ui-text-primary: #e0e6f2;
  --ui-text-secondary: #a6b8cc;
  --ui-text-placeholder: #6a8090;

  /* 强调色系 (统一为深蓝，替换原版绿色) Accents (Deep Blue) */
  --ui-accent-primary: #5090d3;     /* 主强调色 (Win10风格蓝) */
  --ui-accent-primary-hover: #6fa6e8;
  --ui-accent-secondary: #82aaff;   /* 亮蓝色 (链接/高亮) */

  /* 边框与阴影 Borders and Shadows */
  --ui-border-color: rgba(94, 158, 214, 0.25);
  --ui-shadow-color: rgba(0, 0, 0, 0.45);
  --ui-focus-shadow: 0 0 0 2px rgba(80, 144, 211, 0.5);

  /* Mica效果 (磨砂玻璃) Mica Effect */
  --ui-mica-panel: rgba(10, 25, 41, 0.88);      /* 面板Mica */
  --ui-mica-input: rgba(19, 47, 76, 0.85);      /* 输入区Mica */
  --ui-mica-blur: 20px;                         /* 全局模糊强度 */
  --ui-mica-blur-chat: 10px;                    /* 聊天气泡模糊强度 */

  /* 布局参数 Layout Parameters (紧凑化) */
  --ui-border-radius-small: 4px;    /* Win10风格小圆角 */
  --ui-border-radius-medium: 8px;
  --ui-border-radius-large: 12px;   /* 气泡圆角 */
  --ui-spacing: 10px; /* 紧凑间距 */
}

/* === 2. 全局样式与滚动条 Global Styles & Scrollbars === */
body {
  background-color: var(--ui-bg-primary);
  color: var(--ui-text-primary);
}

::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background-color: rgba(255, 255, 255, 0.2);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background-color: var(--ui-accent-primary);
}

#chat {
  border: none !important;
  background: var(--ui-bg-primary) !important;
  /* 添加轻微内阴影增加深度感 */
  box-shadow: inset 0 5px 10px -5px rgba(0, 0, 0, 0.2);
}

/* === 3. QQ风格聊天布局 (头像内置, 紧凑化, 磨砂气泡) === */

.mes {
    display: flex;
    flex-direction: row; /* 关键: 头像和消息水平排列 */
    align-items: flex-start;
    gap: var(--ui-spacing);
    padding: var(--ui-spacing);
    border-radius: var(--ui-border-radius-large);
    margin-bottom: 15px;
    transition: box-shadow 0.3s ease, transform 0.3s ease;

    /* 关键: 应用磨砂效果到气泡 */
    backdrop-filter: blur(var(--ui-mica-blur-chat));
    -webkit-backdrop-filter: blur(var(--ui-mica-blur-chat));
}

/* AI消息样式 */
.mes[is_user=false] {
    background: var(--ui-bg-ai-mica);
    border: 1px solid var(--ui-border-color);
    box-shadow: 0 4px 12px var(--ui-shadow-color);
}

/* 用户消息样式 (头像同样在左侧) */
.mes[is_user=true] {
    background: var(--ui-bg-user-mica);
    /* 用户边框稍微加强以区分 */
    border: 1px solid rgba(80, 144, 211, 0.4);
    box-shadow: 0 4px 15px rgba(30, 58, 95, 0.5);
}

/* 悬停效果 */
.mes:not(.mes_edit):hover {
    transform: translateY(-1px);
    box-shadow: 0 8px 25px var(--ui-shadow-color);
}

/* 重置.mes_block (此布局必需) */
.mes_block {
  padding: 0;
  background: none;
  border: none;
  box-shadow: none;
  backdrop-filter: none;
  -webkit-backdrop-filter: none;
  flex-grow: 1;
}

/* 移除旧版装饰线 */
.mes[is_user=false] .mes_block::before,
.mes[is_user=true] .mes_block::before { display: none; }

/* === 4. 头像与文本细节 Avatar & Text Details === */

.mes .mesAvatarWrapper {
    padding-bottom: 0;
    flex-shrink: 0;
}
/* 紧凑的头像尺寸 */
.mesAvatarWrapper .avatar img, .mesAvatarWrapper .avatar {
    width: 46px;
    height: 46px;
    border-radius: 50%; /* 圆形头像 */
}

/* 头像边框和阴影 (Win10风格) */
.mesAvatarWrapper .avatar img {
  border: 2px solid transparent;
  transition: all 0.3s ease;
}
/* AI头像 (次要色边框) */
.mes[is_user=false] .mesAvatarWrapper .avatar img {
  border-color: var(--ui-text-secondary);
  box-shadow: 0 0 10px rgba(166, 184, 204, 0.4);
}
/* 用户头像 (主强调色边框) */
.mes[is_user=true] .mesAvatarWrapper .avatar img {
  border-color: var(--ui-accent-primary);
  box-shadow: 0 0 12px rgba(80, 144, 211, 0.6);
}
.mesAvatarWrapper .avatar img:hover {
  transform: scale(1.08);
  box-shadow: 0 0 20px rgba(80, 144, 211, 0.8);
}

/* 文本样式 */


/* 链接 */
.mes_text a {
  color: var(--ui-accent-secondary);
  text-decoration: underline;
}

/* 时间戳和元数据 */
.mesIDDisplay, .mes_timer, .tokenCounterDisplay {
    margin: 0 5px;
    color: var(--ui-text-secondary);
    opacity: 0.7;
    font-size: 0.85em;
}

/* === 5. 核心布局调整与Bug修复 (底部设置栏) === */

/* 1. 隐藏实际的顶部栏容器 */
#top-bar {
    height: 0px !important;
    background: none !important;
    border: none !important;
    overflow: visible !important;
    padding: 0 !important;
    pointer-events: none; /* 防止隐藏后阻挡交互 */
}

/* 2. 将设置栏置于底部 */
#top-settings-holder {
  /* 保持absolute定位通常能更好地与SillyTavern的布局计算协同工作 */
  position: absolute; 
  bottom: 0px !important;
  top: auto !important; /* 明确设置top为auto防止冲突 */
  width: 100%;
  z-index: 1001;
  pointer-events: auto; /* 允许交互 */

  /* 应用Mica效果 */
  background: var(--ui-mica-panel);
  backdrop-filter: blur(var(--ui-mica-blur));
  -webkit-backdrop-filter: blur(var(--ui-mica-blur));
  border-top: 1px solid var(--ui-accent-primary); /* 顶部蓝色强调线 */
  box-shadow: 0 -4px 20px var(--ui-shadow-color);
}

/* 3. 关键Bug修复: 解决模糊效果导致设置界面卡在屏幕下方的问题 */
/* 当父元素启用模糊(backdrop-filter)时，子元素的定位可能会受影响。*/
#top-settings-holder .drawer .drawer-content {
    /* 使用fixed定位，使其相对于视窗定位，从而摆脱父元素模糊效果的影响 */
    position: fixed; 
    /* 锚定在设置栏上方 (依赖JS计算的var(--topBarBlockSize)) */
    bottom: var(--topBarBlockSize, 45px); 
    top: auto !important; 
    /* 限制最大高度，防止溢出屏幕顶部，并允许滚动 */
    max-height: calc(100vh - var(--topBarBlockSize, 45px) - 10px); 
    overflow-y: auto;

    /* 样式美化 */
    background: var(--ui-mica-panel) !important;
    backdrop-filter: blur(var(--ui-mica-blur));
    -webkit-backdrop-filter: blur(var(--ui-mica-blur));
    border: 1px solid var(--ui-border-color);
    border-bottom: none;
    /* 确保弹出菜单的宽度和位置与图标对齐 (由SillyTavern JS处理left/right属性) */
    border-radius: var(--ui-border-radius-medium) var(--ui-border-radius-medium) 0 0;
}

/* 4. 调整侧边栏定位和高度 */

#left-nav-panel, #right-nav-panel {
  /* 高度计算: 100vh - 底部总高度(设置栏+输入区) - 上下边距 */
  /* 底部总高度依赖 var(--bottomFormBlockSize) 和 var(--topBarBlockSize) */
  height: calc(100dvh - var(--bottomFormBlockSize, 60px) - var(--topBarBlockSize, 45px) - 20px) !important;
  max-height: calc(100dvh - var(--bottomFormBlockSize, 60px) - var(--topBarBlockSize, 45px) - 20px) !important;
  border-radius: var(--ui-border-radius-medium);

  /* 应用Mica效果到侧边栏 */
  background-color: var(--ui-mica-panel);
  backdrop-filter: blur(var(--ui-mica-blur));
  -webkit-backdrop-filter: blur(var(--ui-mica-blur));
  border: 1px solid var(--ui-border-color);
  box-shadow: 0 4px 15px var(--ui-shadow-color);
}

/* === 6. 兼容性修复: 禁用模糊效果 (no-blur模式) === */
/* 当禁用模糊效果时，提供纯色背景并确保定位正确 */

/* 面板和设置栏使用纯色背景 */
body.no-blur #top-settings-holder,
body.no-blur #left-nav-panel,
body.no-blur #right-nav-panel,
body.no-blur #top-settings-holder .drawer .drawer-content,
body.no-blur .popup:not(.transparent_dialogue_popup) {
    background: var(--ui-bg-primary) !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
}

/* 聊天气泡使用纯色背景 */
body.no-blur .mes {
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
}
body.no-blur .mes[is_user=false] { background: var(--ui-bg-ai-solid); }
body.no-blur .mes[is_user=true] { background: var(--ui-bg-user-solid); }

/* 再次确认no-blur模式下的定位规则 (应与模糊模式保持一致以确保稳定性) */
body.no-blur #top-settings-holder {
  position: absolute;
  bottom: 0px !important;
}
body.no-blur #top-settings-holder .drawer .drawer-content {
    position: fixed;
    bottom: var(--topBarBlockSize, 45px);
}

/* === 7. UI元素美化 (Win10/深蓝磨砂风格) === */

/* --- 设置项和标题 Headers and Titles --- */
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader, .inline-drawer-header {
  /* Win10风格: 细微背景和强烈的左侧边框 */
  background: rgba(19, 47, 76, 0.6);
  color: var(--ui-text-primary);
  border-left: 4px solid var(--ui-accent-primary);
  padding-left: 10px;
  border-radius: 0 var(--ui-border-radius-small) var(--ui-border-radius-small) 0;
  margin-bottom: 8px;
}

/* --- 输入框和文本域 Inputs and Textareas --- */
input[type="text"], input[type="number"], input[type="password"], textarea, .text_pole, select {
  background-color: var(--ui-bg-secondary) !important;
  border: 1px solid var(--ui-border-color) !important;
  color: var(--ui-text-primary) !important;
  border-radius: var(--ui-border-radius-small);
  transition: border-color 0.2s, box-shadow 0.2s;
}
input:focus, textarea:focus, .text_pole:focus, select:focus {
  border-color: var(--ui-accent-primary) !important;
  box-shadow: var(--ui-focus-shadow);
  outline: none;
}
::placeholder { color: var(--ui-text-placeholder) !important; }

/* --- 按钮 Buttons --- */
.menu_button, button {
  background-color: var(--ui-bg-secondary);
  color: var(--ui-text-primary);
  border: 1px solid var(--ui-border-color);
  border-radius: var(--ui-border-radius-small);
  transition: background-color 0.2s ease, border-color 0.2s ease, transform 0.1s ease;
  box-shadow: none; text-shadow: none;
}
.menu_button:hover, button:hover {
  background-color: rgba(19, 47, 76, 0.8);
  border-color: var(--ui-accent-primary);
  transform: translateY(-1px);
}
.menu_button:active, button:active {
  background-color: var(--ui-accent-primary);
  color: var(--ui-bg-primary);
  transform: translateY(0);
}

/* --- 复选框 Checkboxes (Win10 style) --- */
input[type="checkbox"] {
  appearance: none; -webkit-appearance: none;
  width: 16px; height: 16px;
  border: 1px solid var(--ui-border-color);
  border-radius: 3px;
  background-color: var(--ui-bg-secondary);
  position: relative; cursor: pointer; filter: none; box-shadow: none;
}
input[type="checkbox"]:checked {
  background-color: var(--ui-accent-primary);
  border-color: var(--ui-accent-primary);
}
input[type="checkbox"]:checked::before {
  content: '✔'; position: absolute; top: 50%; left: 50%;
  transform: translate(-50%, -50%); font-size: 12px;
  color: var(--ui-bg-primary); line-height: 1;
}

/* === 8. 发送区域与图标优化 Send Area & Icons === */

/* 发送区域背景 (使用输入区Mica) */
#send_form {
    background: var(--ui-mica-input) !important;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border-top: 1px solid var(--ui-border-color);
}

/* 主输入框 */
#send_textarea {
  background: rgba(10, 25, 41, 0.7) !important; /* 深色背景以区分 */
  border-radius: var(--ui-border-radius-medium) !important;
  field-sizing: unset;
  min-height: 36px !important; /* 紧凑高度 */
  border: 1px solid var(--ui-border-color) !important;
  color: var(--ui-text-primary) !important;
  transition: all 0.2s ease;
  padding: 8px 12px !important;
}
#send_textarea:focus {
  border-color: var(--ui-accent-primary) !important;
  box-shadow: var(--ui-focus-shadow);
}

/* 底部设置栏图标 */
#top-settings-holder .drawer-icon { transition: color 0.2s, opacity 0.2s; opacity: 0.8; }
#top-settings-holder .drawer-icon:before { font-size: 22px; color: var(--ui-text-secondary); }
#top-settings-holder .drawer-icon:hover:before,
#top-settings-holder .drawer:focus-within .drawer-icon:before {
    color: var(--ui-accent-primary); opacity: 1;
}
#top-settings-holder .openIcon:before,
#top-settings-holder .openIcon:hover:before { color: var(--ui-accent-primary); }

/* 发送区域图标 */
#nonQRFormItems .fa-solid::before,
#nonQRFormItems .fa-regular::before {
    font-size: 20px; color: var(--ui-text-secondary); transition: color 0.2s;
}
#nonQRFormItems .fa-solid:hover::before,
#nonQRFormItems .fa-regular:hover::before { color: var(--ui-accent-primary); }

/* 发送按钮 */
#send_but:before { color: var(--ui-accent-primary) !important; transition: color 0.2s; }
#send_but:hover:before { color: var(--ui-accent-primary-hover) !important; }

/* === 9. 细节优化 Details === */

/* 代码块 */
.mes_text pre, .mes_reasoning pre {
  background: var(--ui-bg-tertiary);
  border: 1px solid var(--ui-border-color);
  border-radius: var(--ui-border-radius-medium);
  padding: 1em;
}
.mes_text code, .mes_reasoning code {
  color: var(--ui-text-primary);
}

/* 快速回复按钮 (深蓝风格，替换绿色) */
#qr--bar > .qr--buttons .qr--button,
#qr--popout > .qr--body > .qr--buttons .qr--button {
  background: rgba(80, 144, 211, 0.2) !important;
  border: 1px solid var(--ui-accent-primary) !important;
  color: var(--ui-accent-primary) !important;
  border-radius: var(--ui-border-radius-small) !important;
  transition: all 0.2s ease;
}
#qr--bar > .qr--buttons .qr--button:hover,
#qr--popout > .qr--body > .qr--buttons .qr--button:hover {
  background: rgba(80, 144, 211, 0.4) !important;
  transform: translateY(-1px);
}

/* 消息操作按钮 */
.mes_button, .extraMesButtons>div {
    filter: unset; opacity: 0.7; color: var(--ui-text-secondary); transition: all 0.2s ease;
}
.mes_button:hover, .extraMesButtons>div:hover {
    opacity: 1; color: var(--ui-accent-primary);
}
/* 修复用户消息编辑按钮颜色 */
.mes[is_user=true] .mes_edit_buttons *:before {color: var(--ui-text-secondary) !important}
.mes[is_user=true] .mes_edit_buttons *:hover:before {color: var(--ui-accent-primary) !important}

/* 思考内容(Thought)按钮 */
.mes_reasoning button {
  background-color: var(--ui-bg-secondary);
  color: var(--ui-text-secondary);
  border: 1px solid var(--ui-border-color);
  border-radius: var(--ui-border-radius-medium);
  transition: all 0.2s ease;
}
.mes_reasoning button:hover {
  background-color: var(--ui-bg-user-solid);
  border-color: var(--ui-accent-primary);
  color: var(--ui-text-primary);
}

/* 弹出窗口 (Popups) Mica效果 */
#dialogue_popup, #character_popup, #select_chat_popup,
.popup:not(.transparent_dialogue_popup) {
  background-color: var(--ui-mica-panel) !important;
  backdrop-filter: blur(var(--ui-mica-blur));
  -webkit-backdrop-filter: blur(var(--ui-mica-blur));
  border: 1px solid var(--ui-border-color);
  border-radius: var(--ui-border-radius-large);
  box-shadow: 0 10px 30px var(--ui-shadow-color);
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
  color: var(--ui-accent-primary);
}
/* === Patch A: 贴顶显示，移除顶部留白（含安全区） === */
:root {
  --safe-top: env(safe-area-inset-top, 0px);
}

/* 遮罩层贴顶 */
#sheld, .openDrawer { 
  position: fixed !important; 
  top: var(--safe-top) !important; 
}

/* 所有侧栏/浮动面板都贴顶 */
#right-nav-panel, #left-nav-panel, #floatingPrompt, #cfgConfig, #logprobsViewer, #movingDivs>div {
  top: var(--safe-top) !important;
}

/* 重新计算侧栏高度以匹配贴顶布局 */
#left-nav-panel, #right-nav-panel {
  /* 高度 = 视窗总高度 - 底部输入区高度 - 底部设置栏高度 - 顶部安全区高度 */
  height: calc(100dvh - var(--bottomFormBlockSize, 60px) - var(--topBarBlockSize, 45px) - var(--safe-top)) !important;
  max-height: calc(100dvh - var(--bottomFormBlockSize, 60px) - var(--topBarBlockSize, 45px) - var(--safe-top)) !important;
}

/* 修复no-blur模式下的弹出菜单定位，也让它贴顶 */
body.no-blur #top-settings-holder .drawer .drawer-content {
  position: fixed !important;
  top: var(--safe-top) !important; /* 从顶部开始 */
  bottom: var(--topBarBlockSize, 45px) !important; /* 在底部设置栏上方结束 */
  height: auto !important; /* 高度自动，替代原先复杂的计算 */
  max-height: calc(100vh - var(--topBarBlockSize, 45px) - var(--safe-top)) !important;
}

/* === Patch B: 整体更暗一点（保持风格不变） === */
:root {
  --ui-bg-primary: #071523 !important;     /* 比 #0a1929 更暗一点 */
  --ui-bg-secondary: #0f2438 !important;   /* 比 #132f4c 更暗一点 */
  --ui-bg-tertiary: #00121f !important;

  --ui-mica-panel: rgba(7, 21, 35, 0.92) !important;
  --ui-mica-input: rgba(15, 36, 56, 0.90) !important;

  --ui-bg-user-mica: rgba(24, 46, 74, 0.86) !important;  /* 略暗 + 稍增不透明度 */
  --ui-bg-ai-mica:   rgba(14, 22, 34, 0.86) !important;

  --ui-border-color: rgba(94, 158, 214, 0.18) !important; /* 边框略淡，减少噪点 */
}

/* 让聊天区更“沉”一点的小阴影微调（可选） */
#chat { box-shadow: inset 0 6px 14px -6px rgba(0,0,0,0.28) !important; }

/* === 补丁: 整体颜色加深 (增强版) === */
/* 描述: 将所有蓝色系调整为更深、更饱和的色调，营造沉稳的深海蓝效果。 */
:root {
  /* --- 背景色系 (更深的蓝色) --- */
  --ui-bg-primary: #05101c !important;         /* 主背景色 (原: #0a1929) */
  --ui-bg-secondary: #0d243b !important;       /* 次要背景 (原: #132f4c) */
  --ui-bg-tertiary: #010c18 !important;        /* 最深背景 (原: #011627) */

  /* --- 聊天气泡 (更深的半透明蓝色) --- */
  --ui-bg-user-mica: rgba(22, 48, 82, 0.88) !important;    /* 用户消息 (更不透明，颜色更深) */
  --ui-bg-ai-mica: rgba(12, 22, 36, 0.88) !important;      /* AI消息 (更不透明，颜色更深) */
  /* 纯色备用 (对应调整) */
  --ui-bg-user-solid: #163052 !important; /* (原: #1e3a5f) */
  --ui-bg-ai-solid: #0c1624 !important;   /* (原: #141e2d) */

  /* --- 关键: 强调色系 (更深的蓝色) --- */
  --ui-accent-primary: #337ab7 !important;     /* 主强调色 (更经典的深蓝, 原: #5090d3) */
  --ui-accent-primary-hover: #4a90d6 !important; /* (原: #6fa6e8) */
  --ui-accent-secondary: #70a1ff !important;   /* 亮蓝色 (略微降低亮度, 原: #82aaff) */

  /* --- Mica效果 (更深的面板) --- */
  --ui-mica-panel: rgba(5, 16, 28, 0.92) !important;      /* 面板Mica */
  --ui-mica-input: rgba(13, 36, 59, 0.9) !important;      /* 输入区Mica */

  /* --- 边框与阴影 (配合深色背景调整) --- */
  --ui-border-color: rgba(60, 120, 190, 0.22) !important;
  --ui-focus-shadow: 0 0 0 2px rgba(51, 122, 183, 0.5) !important;
}
